#!/usr/bin/env node
/**
 * Start ONLY the townhouse Fastify API server (no Docker orchestration).
 *
 * Townhouse's `up` command bundles container orchestration + API startup.
 * For demos that already have containers running via `townhouse-dev-infra.sh`,
 * we just need the API on :9400 to feed the dashboard at :5173. This launcher
 * builds the same `ApiDeps` `up` constructs, then calls `createApiServer` and
 * listens.
 *
 * Reads:
 *   ~/.townhouse/config.yaml — generated by `town demo --yes` / `townhouse init`
 *   ~/.townhouse/wallet.enc  — same
 *
 * Env:
 *   TOWNHOUSE_WALLET_PASSWORD  — wallet password (defaults to demo password)
 *   TOWNHOUSE_CONFIG           — override config path
 *
 * Notes:
 *   - The orchestrator is constructed but never told to .up() anything; the
 *     dashboard's /api/nodes still works because it reads container state via
 *     dockerode.listContainers(), filtering by name prefix. With our
 *     dev-compose containers prefixed `townhouse-dev-` (vs orchestrator's
 *     default `townhouse-`), some panels may show no nodes — that's a known
 *     gap, not the goal of this script.
 */

import { homedir } from 'node:os';
import { join } from 'node:path';

import Docker from 'dockerode';

import {
  loadConfig,
  WalletManager,
  loadWallet,
  decryptWallet,
  ConnectorAdminClient,
  TransportProbe,
  DEFAULT_ATOR_PROXY,
  DockerOrchestrator,
  createApiServer,
} from '@toon-protocol/hub';

import { readFileSync, existsSync } from 'node:fs';

const DEMO_PASSWORD = 'townhouse-demo-INSECURE-do-not-use-in-prod';
const password = process.env.TOWNHOUSE_WALLET_PASSWORD ?? DEMO_PASSWORD;
const configPath =
  process.env.TOWNHOUSE_CONFIG ?? join(homedir(), '.townhouse', 'config.yaml');

// Auto-load Akash chain endpoints + contract addresses from leases.json so
// the wallet/withdraw and chain-aware routes resolve to our deployed chains
// instead of localhost defaults. Both env vars below are read by the legacy
// wallet routes; resolveChainConfig also reads TOON_RPC_URL.
const leasesPath = join(
  process.cwd(),
  '..',
  '..',
  'deploy',
  'akash',
  'leases.json'
);
if (existsSync(leasesPath)) {
  try {
    const leases = JSON.parse(readFileSync(leasesPath, 'utf-8'));
    if (leases.anvil?.url) {
      process.env.TOWNHOUSE_DEV_ANVIL_RPC ??= leases.anvil.url;
      process.env.TOON_RPC_URL ??= leases.anvil.url;
    }
    if (leases.solana?.url) {
      process.env.SOLANA_RPC_URL ??= leases.solana.url;
    }
  } catch (err) {
    console.warn('[api-only] could not parse leases.json:', err.message);
  }
}
// Mock USDC is deterministic on the deployer's nonce — same address on every
// fresh anvil boot. Verified via eth_getCode on the running Akash anvil.
process.env.TOON_USDC_ADDRESS ??= '0x5FbDB2315678afecb367f032d93F642f64180aa3';

console.log('[api-only] chain endpoints:');
console.log(`  TOON_RPC_URL          = ${process.env.TOON_RPC_URL ?? '(unset)'}`);
console.log(`  SOLANA_RPC_URL        = ${process.env.SOLANA_RPC_URL ?? '(unset)'}`);
console.log(`  TOWNHOUSE_DEV_ANVIL   = ${process.env.TOWNHOUSE_DEV_ANVIL_RPC ?? '(unset)'}`);
console.log(`  TOON_USDC_ADDRESS     = ${process.env.TOON_USDC_ADDRESS}`);

console.log(`[api-only] config: ${configPath}`);

const config = loadConfig(configPath);
const walletPath = config.wallet.encrypted_path;
console.log(`[api-only] wallet: ${walletPath}`);

const loaded = await loadWallet(walletPath);
if (!loaded) {
  console.error(`No wallet at ${walletPath}. Run \`town demo --yes --force\` first.`);
  process.exit(1);
}
if (loaded.permissionsWarning) {
  console.warn(loaded.permissionsWarning);
}

const mnemonic = decryptWallet(loaded.wallet, password);
const walletManager = new WalletManager({ encryptedPath: walletPath });
await walletManager.fromMnemonic(mnemonic);
console.log('[api-only] wallet decrypted');

const docker = new Docker();
const orchestrator = new DockerOrchestrator(docker, config, walletManager);

const connectorAdmin = new ConnectorAdminClient(
  `http://127.0.0.1:${config.connector.adminPort}`
);
console.log(
  `[api-only] connector admin: http://127.0.0.1:${config.connector.adminPort}`
);

const transportProbe = new TransportProbe({
  proxyUrl:
    config.transport.mode === 'ator'
      ? config.transport.socksProxy ?? DEFAULT_ATOR_PROXY
      : '',
});
if (config.transport.mode === 'ator') {
  transportProbe.start();
}

const apiServer = await createApiServer({
  configPath,
  config,
  orchestrator,
  wallet: walletManager,
  connectorAdmin,
  transportProbe,
});

const host = config.api.host ?? '127.0.0.1';
const port = config.api.port ?? 9400;
await apiServer.app.listen({ host, port });
console.log(`[api-only] listening on http://${host}:${port}`);

// Graceful shutdown
const shutdown = async (sig) => {
  console.log(`\n[api-only] ${sig} — closing...`);
  try {
    transportProbe.stop();
  } catch {}
  try {
    await apiServer.app.close();
  } catch {}
  process.exit(0);
};
process.on('SIGINT', () => shutdown('SIGINT'));
process.on('SIGTERM', () => shutdown('SIGTERM'));
